import React, { useEffect, useState } from 'react'
import { farmService } from '../../services/api'

const emptyForm = {
  farm_code: '',
  farm_name: '',
  location: '',
  area_hectare: '',
}

const OwnerFarms = () => {
  const [farms, setFarms] = useState([])
  const [loading, setLoading] = useState(false)
  const [editingId, setEditingId] = useState(null)
  const [error, setError] = useState('')
  const [showModal, setShowModal] = useState(false)
  const [saving, setSaving] = useState(false)
  const [form, setForm] = useState(emptyForm)

  const loadFarms = async () => {
    setLoading(true)
    try {
      const res = await farmService.getFarms()
      setFarms(res.data.data || [])
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => { loadFarms() }, [])

  const openCreateModal = () => {
    setEditingId(null)
    setForm(emptyForm)
    setShowModal(true)
  }

  const handleEdit = (farm) => {
    setEditingId(farm.farm_id)
    setForm({
      farm_code: farm.farm_code || '',
      farm_name: farm.farm_name || '',
      location: farm.location || '',
      area_hectare: farm.area_hectare ?? '',
    })
    setShowModal(true)
  }

  const handleDelete = async (farmId) => {
    if (!window.confirm('Bạn có chắc chắn muốn xóa trại này?')) return
    try {
      await farmService.deleteFarm(farmId)
      await loadFarms()
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    }
  }

  const handleChange = (e) => {
    const { name, value } = e.target
    setForm((f) => ({ ...f, [name]: value }))
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setSaving(true)
    setError('')
    try {
      if (editingId) {
        await farmService.updateFarm(editingId, form)
      } else {
        await farmService.createFarm(form)
      }
      setShowModal(false)
      setEditingId(null)
      setForm(emptyForm)
      await loadFarms()
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    } finally {
      setSaving(false)
    }
  }

  return (
    <div style={{ padding: 20 }}>
      <h2>Quản lý Trại nuôi</h2>
      {error && <div className="alert alert-error">{error}</div>}

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <div>
          <h2>Quản lý Trại nuôi</h2>
          <p style={{ margin: 0, color: '#666' }}>Tạo, sửa và xóa trại.</p>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <button onClick={openCreateModal} className="btn btn-primary">+ Tạo trại mới</button>
        </div>
      </div>

      <h3>Danh sách trại</h3>
      {loading ? (
        <p>Đang tải...</p>
      ) : (
        <table className="table">
          <thead>
            <tr>
              <th>#</th>
              <th>Mã</th>
              <th>Tên</th>
              <th>Địa điểm</th>
              <th>Diện tích (ha)</th>
              <th>Hành động</th>
            </tr>
          </thead>
          <tbody>
            {farms.map((f, idx) => (
              <tr key={f.farm_id}>
                <td>{idx + 1}</td>
                <td>{f.farm_code}</td>
                <td>{f.farm_name}</td>
                <td>{f.location}</td>
                <td>{f.area_hectare}</td>
                <td>
                  <button className="btn" onClick={() => handleEdit(f)}>Sửa</button>
                  <button className="btn btn-danger" onClick={() => handleDelete(f.farm_id)}>Xóa</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {showModal && (
        <div className="modal" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: 720 }}>
            <h3 style={{ marginTop: 0 }}>{editingId ? 'Cập nhật trại' : 'Tạo trại mới'}</h3>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Mã trại</label>
                <input name="farm_code" value={form.farm_code} onChange={handleChange} required />
              </div>
              <div className="form-group">
                <label>Tên trại</label>
                <input name="farm_name" value={form.farm_name} onChange={handleChange} required />
              </div>
              <div className="form-group">
                <label>Địa điểm</label>
                <input name="location" value={form.location} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label>Diện tích (ha)</label>
                <input name="area_hectare" value={form.area_hectare} onChange={handleChange} />
              </div>

              <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
                <button className="btn btn-primary" type="submit" disabled={saving}>{saving ? 'Đang lưu...' : 'Lưu'}</button>
                <button type="button" className="btn" onClick={() => setShowModal(false)}>Hủy</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default OwnerFarms
